#include <stdio.h>
#include <limits.h>
#define MAX_N 10
#define MAX_M 45
#define MAX_D 20
int N, M;
int dist[MAX_N][MAX_N];
int main() {
    scanf("%d %d", &N, &M);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (i == j) dist[i][j] = 0;
            else dist[i][j] = INT_MAX;
        }
    }
    for (int i = 0; i < M; i++) {
        int A, B, D;
        scanf("%d %d %d", &A, &B, &D);
        dist[A][B] = D;
        dist[B][A] = D;
    }
    // Floyd-Warshall algorithm
    for (int k = 0; k < N; k++) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (dist[i][k] != INT_MAX && dist[k][j] != INT_MAX) {
                    dist[i][j] = (dist[i][j] < dist[i][k] + dist[k][j]) ? dist[i][j] : dist[i][k] + dist[k][j];
                }
            }
        }
    }
    int sum = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (dist[i][j] < INT_MAX && dist[i][j] < dist[j][i]) {
                sum += dist[i][j];
            }
        }
    }
    printf("%d/1\n", sum);
    return 0;
}

